import React, { useEffect, useRef } from 'react';

const Background: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let time = 0;

    // Configuration for DNA strands
    const strands = [
      { xOffset: 0.2, color: 'rgba(14, 165, 233, 0.15)', speed: 0.002, amplitude: 60 }, // Blue
      { xOffset: 0.5, color: 'rgba(99, 102, 241, 0.15)', speed: 0.003, amplitude: 80 }, // Indigo
      { xOffset: 0.8, color: 'rgba(148, 163, 184, 0.15)', speed: 0.0025, amplitude: 50 }, // Slate
    ];

    // Floating particles (omics data points)
    const particles: { x: number; y: number; r: number; vy: number; vx: number; alpha: number }[] = [];
    const particleCount = 40;

    for (let i = 0; i < particleCount; i++) {
      particles.push({
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        r: Math.random() * 2 + 1,
        vy: (Math.random() - 0.5) * 0.5,
        vx: (Math.random() - 0.5) * 0.5,
        alpha: Math.random() * 0.5 + 0.1
      });
    }

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    const drawHelix = (xPos: number, amplitude: number, phase: number, color: string) => {
      if (!ctx) return;
      ctx.beginPath();
      ctx.strokeStyle = color;
      ctx.lineWidth = 2;

      const strandPoints: {x: number, y: number}[] = [];

      for (let y = 0; y < canvas.height; y += 10) {
        const x = xPos + Math.sin(y * 0.01 + phase) * amplitude;
        strandPoints.push({x, y});
        if (y === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
      }
      ctx.stroke();

      // Draw "base pairs" (dots on the strand)
      ctx.fillStyle = color;
      strandPoints.forEach((p, i) => {
        if (i % 8 === 0) { // spacing
          ctx.beginPath();
          ctx.arc(p.x, p.y, 3, 0, Math.PI * 2);
          ctx.fill();
        }
      });
    };

    const animate = () => {
      if (!canvas || !ctx) return;
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      time++;

      // Draw Strands
      strands.forEach((strand, i) => {
        const xPos = canvas.width * strand.xOffset;
        const phase = time * strand.speed + i; 
        drawHelix(xPos, strand.amplitude, phase, strand.color);

        // Draw a second intertwining strand for double helix effect
        drawHelix(xPos, strand.amplitude, phase + Math.PI, strand.color.replace('0.15', '0.08'));
      });

      // Draw Floating Omics Particles
      ctx.fillStyle = 'rgba(100, 116, 139, 0.4)';
      particles.forEach(p => {
        p.y += p.vy;
        p.x += p.vx;

        // Wrap around screen
        if (p.y < 0) p.y = canvas.height;
        if (p.y > canvas.height) p.y = 0;
        if (p.x < 0) p.x = canvas.width;
        if (p.x > canvas.width) p.x = 0;

        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fill();
      });

      animationFrameId = requestAnimationFrame(animate);
    };

    window.addEventListener('resize', resize);
    resize();
    animate();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <div className="fixed inset-0 z-0 pointer-events-none overflow-hidden bg-slate-50">
      <canvas ref={canvasRef} className="absolute inset-0 w-full h-full" />
      <div className="absolute inset-0 bg-gradient-to-b from-slate-50/50 via-transparent to-slate-50/50"></div>
    </div>
  );
};

